import java.io.FileWriter;
import java.io.IOException;
import org.owasp.encoder.Encode;

public class XSSFixedCode {

    public static void main(String[] args) throws IOException {
        // Simulating user input
        String userInput = "<script>alert('XSS attack!')</script>";

        // Properly escaping user input before outputting it to the HTML response
        FileWriter fileWriter = new FileWriter("output.html");
        fileWriter.write("<html>");
        fileWriter.write("<body>");
        fileWriter.write("<h1>Welcome, " + Encode.forHtml(userInput) + "</h1>");
        fileWriter.write("</body>");
        fileWriter.write("</html>");

        fileWriter.close();
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
